    'Xã Bình Minh': r'(?i)(xã\s+bình\s+minh|bình\s+minh.*xã)',
    'Xã Thạch Bích': r'(?i)(xã\s+thạch\s+bích|thạch\s+bích.*xã)',
}

pages = full_text.split('--- Trang ')
all_matches = {}

for kw, pattern in patterns.items():
    matched_pages = []
    for page in pages:
        if not page.strip():
            continue
        page_num = page.split(' ---')[0].strip()
